$(function(){QUnit.module("util");QUnit.test("Util.getSelectorFromElement should return the correct element",function(a){a.expect(5);var d=$('<div data-target="body"></div>').appendTo($("#qunit-fixture"));a.strictEqual(Util.getSelectorFromElement(d[0]),"body");var e=$('<div data-target="#fakeDiv"></div>').appendTo($("#qunit-fixture"));a.strictEqual(Util.getSelectorFromElement(e[0]),null);var c=$('<div data-target="#collapse:Example"></div>').appendTo($("#qunit-fixture"));$('<div id="collapse:Example"></div>').appendTo($("#qunit-fixture"));a.strictEqual(Util.getSelectorFromElement(c[0]),"#collapse\\:Example");var b=$.escapeSelector;delete $.escapeSelector;a.ok(typeof $.escapeSelector==="undefined","$.escapeSelector undefined");a.strictEqual(Util.getSelectorFromElement(c[0]),"#collapse\\:Example");$.escapeSelector=b});QUnit.test("Util.typeCheckConfig should thrown an error when a bad config is passed",function(a){a.expect(1);var d="collapse";var e={toggle:"boolean",parent:"(string|element)"};var b={toggle:true,parent:777};try{Util.typeCheckConfig(d,b,e)}catch(c){a.strictEqual(c.message,'COLLAPSE: Option "parent" provided type "number" but expected type "(string|element)".')}});QUnit.test("Util.isElement should check if we passed an element or not",function(b){b.expect(3);var a=$('<div id="test"></div>').appendTo($("#qunit-fixture"));b.strictEqual(Util.isElement(a),1);b.strictEqual(Util.isElement(a[0]),1);b.strictEqual(typeof Util.isElement({})==="undefined",true)});QUnit.test("Util.getUID should generate a new id uniq",function(a){a.expect(2);var c=Util.getUID("test");var b=Util.getUID("test");a.ok(c!==b,c+" !== "+b);c=Util.getUID("test");$('<div id="'+c+'"></div>').appendTo($("#qunit-fixture"));b=Util.getUID("test");a.ok(c!==b,c+" !== "+b)})});